/**
 * Mock data for the Data › Customers record-explorer page.
 *
 * Ported from /Users/mac/Downloads/MAGELLAN UX/Data/magellan-data-customers.html
 * Currency converted ฿ → $ (same digits, $ symbol) per Magellan currency rule.
 *
 * The template generates 54 customer records from a seeded RNG so the table is
 * deterministic. We reproduce that generator verbatim (mulberry32 seed 73) and
 * freeze the result into a typed array exported for the page. No randomness at
 * render time — same seed → same rows every build.
 */

/* ─────────────────────────── Types ─────────────────────────── */

export type Segment = "vip" | "repeat" | "lapsing" | "new" | "onetime";
export type FirstSource =
  | "organic"
  | "google_ads"
  | "meta_ads"
  | "direct"
  | "email"
  | "line_oa";

export interface OrderHistoryItem {
  id: string;
  date: string;
  product: string;
  amt: number;
}

export interface DistinctProduct {
  name: string;
  qty: number;
  sku: string;
}

export type LifeKind = "join" | "order" | "repeat" | "vip" | "cold" | "recent";

export interface LifeStep {
  /** title, e.g. "Joined" */
  t: string;
  /** date / when descriptor */
  d: string;
  /** sub line */
  sub: string;
  kind: LifeKind;
}

export interface CustomerRecord {
  id: string;
  name: string;
  email: string;
  phone: string;
  segment: Segment;
  orders: number;
  /** average order value (USD) */
  aov: number;
  monetary: number;
  /** lifetime value (USD) */
  ltv: number;
  /** days since last order */
  recency: number;
  first: string;
  last: string;
  district: string;
  zip: string;
  firstSource: FirstSource;
  ageBand: string;
  ageConf: number;
  gender: string;
  genConf: number;
  hist: OrderHistoryItem[];
  products: DistinctProduct[];
  life: LifeStep[];
  /** behavioral archetype — the decision-grade handoff line */
  archetype: string;
}

export interface ColumnDef {
  k: SortKey;
  label: string;
  /** right-aligned numeric column */
  num?: boolean;
  /** always on, can't be toggled off */
  fixed?: boolean;
  /** off by default */
  off?: boolean;
  /** runtime toggle state (overrides `off` when set) */
  on?: boolean;
}

export type SortKey =
  | "name"
  | "segment"
  | "orders"
  | "aov"
  | "ltv"
  | "recency"
  | "firstSource"
  | "district";

export interface SegmentMeta {
  label: string;
  color: string;
  bg: string;
}

/* ─────────────────────────── Seeded generator (mulberry32) ─────────────────────────── */

function mulberry32(a: number): () => number {
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

const rng = mulberry32(73);
const pick = <T,>(arr: readonly T[]): T => arr[Math.floor(rng() * arr.length)];
const between = (a: number, b: number): number => a + Math.floor(rng() * (b - a + 1));

