export function initials(name: string): string {
  const clean = name
    .split("·")[0]
    .replace(/[^A-Za-z0-9 ]/g, "")
    .trim()
    .split(/\s+/);
  if (clean.length >= 2) return (clean[0][0] + clean[1][0]).toUpperCase();
  return (clean[0] || "").slice(0, 2).toUpperCase();
}
