"use client";

/* ════════════════════════════════════════════════════════════════════════
   DATA › CUSTOMERS — record explorer (drill-down table).
   Port of magellan-data-customers.html. This is the DATA-room customer
   record table (not the Customers department room). Chrome aligned to the
   style guide: canonical DeptHeader + .pt-search + sortable §8.13 table.

   The dept accent is var(--d-data) (compass blue), used as an ACCENT only.
   Currency is USD ($). The trend sparkline is hand-built SVG (no library).
   Everything is scoped under .data-cust.
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState, useRef, useEffect, useLayoutEffect, useCallback } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import {
  customers,
  SEG_META,
  COLUMNS,
  FILTER_CHIPS,
  CAL_PRESETS,
  crossRoom,
  fmtUSD,
  initials,
  type CustomerRecord,
  type SortKey,
  type FilterKey,
  type ColumnDef,
} from "@/features/data/api/data-customers-data";
import "./customers.css";

/* numeric vs string sort keys */
const STRING_KEYS = new Set<SortKey>(["name", "segment", "firstSource", "district"]);

const TODAY = new Date(2026, 4, 26);

function recencyLabel(days: number): string {
  return days === 0 ? "today" : days === 1 ? "1 day ago" : `${days} days ago`;
}

/* ───────────────────────── Trend sparkline (hand-built SVG) ───────────────────────── */

const T_H = 170;
const TPAD = { l: 38, r: 14, t: 14, b: 24 };

function newCustomersPerDay(rows: CustomerRecord[]): number[] {
  // last 30 calendar days ending 2026-05-26, by first-order date
  const buckets: { iso: string; c: number }[] = [];
  for (let i = 29; i >= 0; i--) {
    const d = new Date(TODAY);
    d.setDate(TODAY.getDate() - i);
    buckets.push({ iso: d.toISOString().slice(0, 10), c: 0 });
  }
  const idx: Record<string, number> = {};
  buckets.forEach((b, i) => (idx[b.iso] = i));
  rows.forEach((o) => {
    if (o.first in idx) buckets[idx[o.first]].c++;
  });
  return buckets.map((b) => b.c);
}

function TrendChart({ rows }: { rows: CustomerRecord[] }) {
  const svgRef = useRef<SVGSVGElement | null>(null);
  const tipRef = useRef<HTMLDivElement | null>(null);
  const [vbw, setVbw] = useState(900);

  const cur = useMemo(() => newCustomersPerDay(rows), [rows]);
  const tmax = useMemo(() => Math.max(6, Math.ceil(Math.max(...cur) / 2) * 2), [cur]);

  useLayoutEffect(() => {
    const el = svgRef.current;
    if (!el) return;
    const measure = () =>
      setVbw(Math.max(560, Math.round(el.getBoundingClientRect().width || 900)));
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  const n = cur.length;
  const tX = useCallback(
    (i: number) => TPAD.l + ((vbw - TPAD.l - TPAD.r) * i) / (n - 1),
    [vbw, n],
  );
  const tY = useCallback(
    (v: number) => {
      const top = TPAD.t + 4;
      const bot = T_H - TPAD.b;
      return top + ((tmax - v) / (tmax - 0)) * (bot - top);
    },
    [tmax],
  );

  const buildInner = useCallback(() => {
    const xs = cur.map((_, i) => tX(i));
    const bot = T_H - TPAD.b;
    let s = "";
    [0, tmax / 2, tmax].forEach((g) => {
      const gy = tY(g);
      s += `<line x1="${TPAD.l}" y1="${gy.toFixed(1)}" x2="${vbw - TPAD.r}" y2="${gy.toFixed(1)}" stroke="rgba(0,0,0,${g === 0 ? 0.1 : 0.05})" stroke-width="0.5"/>`;
      s += `<text x="${TPAD.l - 8}" y="${(gy + 3).toFixed(1)}" text-anchor="end" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">${g}</text>`;
    });
    const cp = cur.map((v, i) => `${i ? "L" : "M"} ${xs[i].toFixed(1)} ${tY(v).toFixed(1)}`).join(" ");
    s += `<path d="${cp} L ${xs[n - 1].toFixed(1)} ${bot} L ${xs[0].toFixed(1)} ${bot} Z" fill="rgba(91,124,176,0.13)"/>`;
    s += `<path class="t-line" d="${cp}" stroke="#2a4070" stroke-width="2.5" fill="none" stroke-linecap="round" stroke-linejoin="round"/>`;
    for (let i = 0; i < n; i++) {
      if (i % 3 === 0 && i !== n - 1) {
        s += `<rect x="${(xs[i] - 2).toFixed(1)}" y="${(tY(cur[i]) - 2).toFixed(1)}" width="4" height="4" rx="0.5" fill="#9aabc4"/>`;
      }
    }
    const ex = xs[n - 1];
    const ey = tY(cur[n - 1]);
    s += `<rect x="${(ex - 7).toFixed(1)}" y="${(ey - 7).toFixed(1)}" width="14" height="14" rx="3" fill="rgba(91,124,176,0.18)"/>`;
    s += `<rect x="${(ex - 3.5).toFixed(1)}" y="${(ey - 3.5).toFixed(1)}" width="7" height="7" rx="1" fill="#2a4070"/>`;
    const valY = ey < TPAD.t + 40 ? ey + 18 : ey - 12;
    s += `<text x="${(ex - 12).toFixed(1)}" y="${valY.toFixed(1)}" text-anchor="end" font-family="Inter" font-size="15" font-weight="300" fill="#2a4070" font-variant-numeric="tabular-nums">${cur[n - 1]} today</text>`;
    s += `<text x="${xs[0].toFixed(1)}" y="${T_H - 8}" text-anchor="start" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">30d ago</text>`;
    s += `<text x="${xs[n - 1].toFixed(1)}" y="${T_H - 8}" text-anchor="end" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">today</text>`;
    s += `<g class="t-hover" style="pointer-events:none;opacity:0;transition:opacity .12s"><line class="t-cross" y1="${TPAD.t}" y2="${bot}" stroke="#3a5285" stroke-width="1" stroke-dasharray="3 3"/><rect class="t-hnode" width="11" height="11" rx="2" fill="#2a4070" stroke="#fff" stroke-width="2"/></g>`;
    for (let i = 0; i < n; i++) {
      const left = i === 0 ? TPAD.l : (xs[i - 1] + xs[i]) / 2;
      const right = i === n - 1 ? vbw - TPAD.r : (xs[i] + xs[i + 1]) / 2;
      s += `<rect class="t-hit" data-i="${i}" x="${left.toFixed(1)}" y="${TPAD.t}" width="${(right - left).toFixed(1)}" height="${(bot - TPAD.t).toFixed(1)}" fill="transparent" style="cursor:crosshair"/>`;
    }
    return s;
  }, [cur, n, tmax, tX, tY, vbw]);

  useEffect(() => {
    const svg = svgRef.current;
    if (!svg) return;
    svg.setAttribute("viewBox", `0 0 ${vbw} ${T_H}`);
    svg.innerHTML = buildInner();

    const xs = cur.map((_, i) => tX(i));
    const cy = cur.map((v) => tY(v));

    let reduce = false;
    try {
      reduce = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    } catch {
      reduce = false;
    }
    if (!reduce) {
      const ln = svg.querySelector<SVGPathElement>(".t-line");
      if (ln && ln.getTotalLength) {
        const L = ln.getTotalLength();
        ln.style.transition = "none";
        ln.style.strokeDasharray = String(L);
        ln.style.strokeDashoffset = String(L);
        ln.getBoundingClientRect();
        ln.style.transition = "stroke-dashoffset 0.7s cubic-bezier(0.22,0.61,0.36,1)";
        ln.style.strokeDashoffset = "0";
      }
    }

    // hover
    const layer = svg.querySelector<SVGGElement>(".t-hover");
    const cross = svg.querySelector<SVGLineElement>(".t-cross");
    const node = svg.querySelector<SVGRectElement>(".t-hnode");
    const tip = tipRef.current;
    if (!layer || !cross || !node || !tip) return;

    const offs: Array<() => void> = [];
    svg.querySelectorAll<SVGRectElement>(".t-hit").forEach((r) => {
      const fn = () => {
        const i = Number(r.dataset.i);
        const x = xs[i];
        layer.style.opacity = "1";
        cross.setAttribute("x1", String(x));
        cross.setAttribute("x2", String(x));
        node.setAttribute("x", String(x - 5.5));
        node.setAttribute("y", String(cy[i] - 5.5));
        const d = new Date(TODAY);
        d.setDate(TODAY.getDate() - (29 - i));
        const ds = d.toLocaleDateString("en-GB", { day: "numeric", month: "short" });
        tip.innerHTML = `<div class="tip-month">${ds}</div><div class="tip-row"><span class="tip-dot c"></span>New<b>${cur[i]}</b></div>`;
        const wrap = svg.getBoundingClientRect();
        const px = wrap.left + (x / vbw) * wrap.width;
        const py = wrap.top + (cy[i] / T_H) * wrap.height;
        tip.style.opacity = "1";
        const tw = tip.offsetWidth || 120;
        let lx = px - tw / 2;
        lx = Math.max(8, Math.min(lx, window.innerWidth - tw - 8));
        tip.style.left = lx + "px";
        tip.style.top = py - tip.offsetHeight - 14 + "px";
      };
      r.addEventListener("mousemove", fn);
      r.addEventListener("mouseenter", fn);
      offs.push(() => {
        r.removeEventListener("mousemove", fn);
        r.removeEventListener("mouseenter", fn);
      });
    });
    const hide = () => {
      layer.style.opacity = "0";
      tip.style.opacity = "0";
    };
    svg.addEventListener("mouseleave", hide);
    offs.push(() => svg.removeEventListener("mouseleave", hide));

    return () => offs.forEach((o) => o());
  }, [buildInner, cur, tX, tY, vbw]);

  return (
    <div className="trend-chart">
      <div className="chart-tip" ref={tipRef} />
      <svg ref={svgRef} width="100%" role="img" aria-label="New customers per day, last 30 days" />
    </div>
  );
}

/* ───────────────────────── Page ───────────────────────── */

type Pop = "none" | FilterKey | "date" | "columns";

export default function DataCustomersPage() {
  const [search, setSearch] = useState("");
  const [filters, setFilters] = useState<Record<FilterKey, Set<string>>>({
    segment: new Set(),
    firstSource: new Set(),
    district: new Set(),
  });
  const [sortKey, setSortKey] = useState<SortKey>("ltv");
  const [sortDir, setSortDir] = useState<-1 | 1>(-1);
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [open, setOpen] = useState<Set<string>>(new Set());
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [cols, setCols] = useState<ColumnDef[]>(() => COLUMNS.map((c) => ({ ...c })));
  const [pop, setPop] = useState<Pop>("none");
  const [datePreset, setDatePreset] = useState("all");

  const stop = (e: React.MouseEvent) => e.stopPropagation();

  // close popovers on outside click
  useEffect(() => {
    const onDoc = (e: MouseEvent) => {
      if ((e.target as HTMLElement | null)?.closest?.(".pop, .filter-chip, .btn-util")) return;
      setPop("none");
    };
    document.addEventListener("click", onDoc);
    return () => document.removeEventListener("click", onDoc);
  }, []);

  const visibleCols = cols.filter((c) => c.on ?? !c.off);

  // ── pipeline: filter → sort ──
  const filtered = useMemo(() => {
    let rows = customers.slice();
    const q = search.trim().toLowerCase();
    if (q) {
      rows = rows.filter(
        (o) =>
          o.name.toLowerCase().includes(q) ||
          o.id.toLowerCase().includes(q) ||
          o.segment.includes(q) ||
          o.firstSource.includes(q) ||
          o.district.toLowerCase().includes(q),
      );
    }
    (["segment", "firstSource", "district"] as FilterKey[]).forEach((key) => {
      const set = filters[key];
      if (set.size) rows = rows.filter((o) => set.has(String(o[key])));
    });
    rows.sort((a, b) => {
      if (STRING_KEYS.has(sortKey)) {
        return sortDir * String(a[sortKey]).localeCompare(String(b[sortKey]));
      }
      return sortDir * ((a[sortKey] as number) - (b[sortKey] as number));
    });
    return rows;
  }, [search, filters, sortKey, sortDir]);

  // ── KPIs (live from filtered set) ──
  const kpis = useMemo(() => {
    const total = filtered.length;
    const repeatCust = filtered.filter((o) => o.orders > 1).length;
    const repeatRate = total ? Math.round((repeatCust / total) * 100) : 0;
    const avgLtv = total ? filtered.reduce((s, o) => s + o.ltv, 0) / total : 0;
    const vip = filtered.filter((o) => o.segment === "vip").length;
    const newC = filtered.filter((o) => o.segment === "new").length;
    return { total, repeatRate, avgLtv: Math.round(avgLtv), vip, newC };
  }, [filtered]);

  // ── pagination ──
  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  const curPage = Math.min(page, totalPages);
  const start = (curPage - 1) * pageSize;
  const pageRows = filtered.slice(start, start + pageSize);

  const toggleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(STRING_KEYS.has(k) ? 1 : -1);
    }
  };

  const toggleOpen = (id: string) =>
    setOpen((cur) => {
      const next = new Set(cur);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });

  const toggleSelect = (id: string) =>
    setSelected((cur) => {
      const next = new Set(cur);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });

  const toggleFilterVal = (key: FilterKey, v: string) =>
    setFilters((cur) => {
      const next = { ...cur, [key]: new Set(cur[key]) };
      if (next[key].has(v)) next[key].delete(v);
      else next[key].add(v);
      return next;
    });

  const clearFilter = (key: FilterKey) =>
    setFilters((cur) => ({ ...cur, [key]: new Set<string>() }));

  const resetAll = () => {
    setSearch("");
    setFilters({ segment: new Set(), firstSource: new Set(), district: new Set() });
    setDatePreset("all");
    setPage(1);
  };

  const allOnPageSelected = pageRows.length > 0 && pageRows.every((o) => selected.has(o.id));
  const toggleSelectAll = () =>
    setSelected((cur) => {
      const next = new Set(cur);
      if (allOnPageSelected) pageRows.forEach((o) => next.delete(o.id));
      else pageRows.forEach((o) => next.add(o.id));
      return next;
    });

  // distinct value counts for the filter checklists
  const uniqueVals = useCallback((key: FilterKey) => {
    const m: Record<string, number> = {};
    customers.forEach((o) => {
      const v = String(o[key]);
      m[v] = (m[v] || 0) + 1;
    });
    return Object.entries(m).sort((a, b) => b[1] - a[1]);
  }, []);

  const filterValLabel = (key: FilterKey, v: string) =>
    key === "segment" ? SEG_META[v as keyof typeof SEG_META]?.label ?? v : v;

  const colSpan = visibleCols.length + 2;

  // pager window
  const pagerWin: (number | "…")[] = [];
  for (let p = 1; p <= totalPages; p++) {
    if (p === 1 || p === totalPages || (p >= curPage - 1 && p <= curPage + 1)) pagerWin.push(p);
    else if (pagerWin[pagerWin.length - 1] !== "…") pagerWin.push("…");
  }

  const dateLabel =
    CAL_PRESETS.find((p) => p.key === datePreset)?.label ?? "All time";

  return (
    <div className="data-cust">
      <div className="dept-wrap">
        {/* ── HEADER ── */}
        <DeptHeader
          dept="data"
          title="Customers"
          meta={
            <>
              <span className="live">Live</span> · {customers.length} customers · synced 4 min ago
            </>
          }
          actions={
            <>
              <button className="btn-util" onClick={() => setPop("none")}>Export ↓</button>
              <button
                className="btn-util"
                onClick={(e) => {
                  e.stopPropagation();
                  setPop((p) => (p === "columns" ? "none" : "columns"));
                }}
              >
                Columns
              </button>
              <button className="btn-util primary">+ Saved view</button>
            </>
          }
        />

        <div className="head-pad" />

        {/* ── FILTER / SEARCH ROW ── */}
        <div className="filter-row" onClick={stop}>
          <div className="pt-search">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <circle cx="11" cy="11" r="7" />
              <line x1="21" y1="21" x2="16.5" y2="16.5" />
            </svg>
            <input
              type="text"
              value={search}
              placeholder="Search customers by name, ID, segment, source…"
              onChange={(e) => {
                setSearch(e.target.value);
                setPage(1);
              }}
            />
          </div>

          {FILTER_CHIPS.map((chip) => {
            const set = filters[chip.key];
            const active = set.size > 0;
            return (
              <div className="chip-wrap" key={chip.key}>
                <button
                  className={`filter-chip${active ? " active" : ""}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    setPop((p) => (p === chip.key ? "none" : chip.key));
                  }}
                >
                  {active ? (
                    <>
                      {chip.label} · {set.size}{" "}
                      <span
                        className="x"
                        onClick={(e) => {
                          e.stopPropagation();
                          clearFilter(chip.key);
                        }}
                      >
                        ×
                      </span>
                    </>
                  ) : (
                    <>
                      {chip.label} <span className="caret">▾</span>
                    </>
                  )}
                </button>
                {pop === chip.key && (
                  <div className="pop open" onClick={stop}>
                    <div className="pop-head">Filter by {chip.key === "firstSource" ? "first source" : chip.key}</div>
                    <div className="pop-body">
                      {uniqueVals(chip.key).map(([v, c]) => (
                        <div
                          key={v}
                          className={`check-item${set.has(v) ? " on" : ""}`}
                          onClick={() => toggleFilterVal(chip.key, v)}
                        >
                          <span className="check-box" />
                          {filterValLabel(chip.key, v)}
                          <span className="check-count">{c}</span>
                        </div>
                      ))}
                    </div>
                    <div className="pop-foot">
                      <button className="pop-btn" onClick={() => clearFilter(chip.key)}>Clear</button>
                      <button className="pop-btn primary" onClick={() => { setPage(1); setPop("none"); }}>Apply</button>
                    </div>
                  </div>
                )}
              </div>
            );
          })}

          {/* date chip + calendar popover */}
          <div className="chip-wrap">
            <button
              className={`filter-chip date-chip${datePreset !== "all" ? " active" : ""}`}
              onClick={(e) => {
                e.stopPropagation();
                setPop((p) => (p === "date" ? "none" : "date"));
              }}
            >
              <svg className="cd-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <rect x="3" y="4" width="18" height="17" rx="2" />
                <line x1="3" y1="9" x2="21" y2="9" />
                <line x1="8" y1="2" x2="8" y2="6" />
                <line x1="16" y1="2" x2="16" y2="6" />
              </svg>
              {dateLabel} <span className="caret">▾</span>
            </button>
            {pop === "date" && (
              <DateCalendar
                preset={datePreset}
                onPreset={(k) => {
                  setDatePreset(k);
                  setPage(1);
                }}
                onClose={() => setPop("none")}
              />
            )}
          </div>

          <button className="filter-clear" onClick={resetAll}>Clear all</button>
        </div>

        {/* ── KPI STRIP ── */}
        <div className="kpi-strip">
          <div className="kpi-card" style={{ ["--accent" as string]: "var(--d-data)" }}>
            <div className="kpi-label">Total customers</div>
            <div className="kpi-value">{kpis.total.toLocaleString()}</div>
            <div className="kpi-sub">in current view</div>
            <div className="kpi-prov connected"><span className="pdot" />Connected · WooCommerce</div>
          </div>
          <div className="kpi-card" style={{ ["--accent" as string]: "var(--d-finance)" }}>
            <div className="kpi-label">Repeat rate</div>
            <div className="kpi-value">{kpis.repeatRate}%</div>
            <div className="kpi-sub">bought more than once</div>
            <div className="kpi-prov computed"><span className="pdot" />Computed · from orders</div>
          </div>
          <div className="kpi-card" style={{ ["--accent" as string]: "var(--d-customers)" }}>
            <div className="kpi-label">Avg lifetime value</div>
            <div className="kpi-value"><span className="cur">$</span>{kpis.avgLtv.toLocaleString()}</div>
            <div className="kpi-sub">contribution-based</div>
            <div className="kpi-prov computed"><span className="pdot" />Computed · from orders</div>
          </div>
          <div className="kpi-card" style={{ ["--accent" as string]: "#831843" }}>
            <div className="kpi-label">VIP customers</div>
            <div className="kpi-value">{kpis.vip.toLocaleString()}</div>
            <div className="kpi-sub">{kpis.newC} new this period</div>
            <div className="kpi-prov computed"><span className="pdot" />Computed · behavioral tier</div>
          </div>
        </div>

        {/* ── TREND ── */}
        <div className="trend-card">
          <div className="trend-head">
            <div className="trend-kicker">New customers per day · last 30 days</div>
            <div className="trend-note">reflects current filters · hover any day</div>
          </div>
          <TrendChart rows={filtered} />
        </div>

        {/* ── BULK BAR ── */}
        <div className={`bulkbar${selected.size > 0 ? " show" : ""}`}>
          <span className="bb-count">
            {selected.size} customer{selected.size > 1 ? "s" : ""} selected
          </span>
          <button className="bb-btn">Export selected ↓</button>
          <button className="bb-clear" onClick={() => setSelected(new Set())}>Clear selection</button>
        </div>

        {/* ── RECORDS HEAD ── */}
        <div className="records-head controls-meta">
          <div className="left"><span className="records-title">Customer records</span></div>
          <div className="records-count">
            {filtered.length
              ? `Showing ${start + 1}–${Math.min(start + pageSize, filtered.length)} of ${filtered.length}`
              : "No matching records"}
          </div>
        </div>

        {/* ── TABLE ── */}
        <div className="table-wrap">
          <div className="table-scroll">
            <table className="otable">
              <thead>
                <tr>
                  <th style={{ width: 30 }} />
                  <th style={{ width: 34 }}>
                    <span
                      className={`row-check${allOnPageSelected ? " on" : ""}`}
                      onClick={toggleSelectAll}
                    />
                  </th>
                  {visibleCols.map((c) => {
                    const sorted = sortKey === c.k;
                    return (
                      <th
                        key={c.k}
                        className={`${c.num ? "num" : ""}${sorted ? " sorted" : ""}`}
                        onClick={() => toggleSort(c.k)}
                      >
                        {c.label}{" "}
                        <span className="sortcaret">{sorted ? (sortDir === 1 ? "▴" : "▾") : "▾"}</span>
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr>
                    <td colSpan={colSpan}>
                      <div className="empty-state">
                        <div className="es-icon">
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                            <circle cx="11" cy="11" r="7" />
                            <line x1="21" y1="21" x2="16.5" y2="16.5" />
                          </svg>
                        </div>
                        <div className="es-title">No customers match this view</div>
                        <div className="es-sub">Try widening the date range or clearing a filter.</div>
                        <button className="es-btn" onClick={resetAll}>Clear all filters</button>
                      </div>
                    </td>
                  </tr>
                ) : (
                  pageRows.map((o) => {
                    const isOpen = open.has(o.id);
                    const isSel = selected.has(o.id);
                    return (
                      <Row
                        key={o.id}
                        o={o}
                        cols={visibleCols}
                        isOpen={isOpen}
                        isSel={isSel}
                        colSpan={colSpan}
                        onToggle={() => toggleOpen(o.id)}
                        onSelect={() => toggleSelect(o.id)}
                      />
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {filtered.length > 0 && (
            <div className="pager">
              <div className="pager-size">
                Rows{" "}
                <select
                  value={pageSize}
                  onChange={(e) => {
                    setPageSize(Number(e.target.value));
                    setPage(1);
                  }}
                >
                  {[10, 20, 50].map((nn) => (
                    <option key={nn} value={nn}>{nn}</option>
                  ))}
                </select>
              </div>
              <div className="pager-ctrl">
                <button className="pager-btn" disabled={curPage === 1} onClick={() => setPage(curPage - 1)}>‹</button>
                {pagerWin.map((p, i) =>
                  p === "…" ? (
                    <span key={`e${i}`} style={{ color: "var(--ink-3)", padding: "0 4px" }}>…</span>
                  ) : (
                    <button key={p} className={`pager-btn${p === curPage ? " on" : ""}`} onClick={() => setPage(p)}>{p}</button>
                  ),
                )}
                <button className="pager-btn" disabled={curPage === totalPages} onClick={() => setPage(curPage + 1)}>›</button>
              </div>
            </div>
          )}
        </div>

        {/* ── CROSS-ROOM FOOTER ── */}
        <div className="crossroom">
          <span className="cr-label">This record feeds</span>
          {crossRoom.map((c, i) => (
            <span key={c.strong} style={{ display: "contents" }}>
              <div className="cr-item">
                <span className="cr-dot" style={{ background: c.dot }} />
                <strong>{c.strong}</strong> — {c.rest}
              </div>
              {i < crossRoom.length - 1 && <div className="cr-sep" />}
            </span>
          ))}
        </div>
      </div>

      {/* columns popover (anchored top-right under the action) */}
      {pop === "columns" && (
        <div className="pop columns-pop open" onClick={stop}>
          <div className="pop-head">Show columns</div>
          <div className="pop-body">
            {cols.map((c) => {
              const on = c.on ?? !c.off;
              return (
                <div
                  key={c.k}
                  className={`check-item${on ? " on" : ""}`}
                  style={c.fixed ? { opacity: 0.5, pointerEvents: "none" } : undefined}
                  onClick={() => {
                    if (c.fixed) return;
                    setCols((cur) => cur.map((x) => (x.k === c.k ? { ...x, on: !(x.on ?? !x.off) } : x)));
                  }}
                >
                  <span className="check-box" />
                  {c.label}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

/* ───────────────────────── Table row + detail ───────────────────────── */

function cellFor(o: CustomerRecord, k: SortKey): React.ReactNode {
  switch (k) {
    case "name":
      return (
        <>
          <div className="oname">{o.name}</div>
          <div className="odate">{o.id} · {o.district}</div>
        </>
      );
    case "segment": {
      const m = SEG_META[o.segment];
      return <span className="pill" style={{ background: m.bg, color: m.color }}>{m.label}</span>;
    }
    case "orders":
      return o.orders;
    case "aov":
      return fmtUSD(o.aov);
    case "ltv":
      return fmtUSD(o.ltv);
    case "recency":
      return <span className={o.recency > 90 ? "margin-thin" : ""}>{recencyLabel(o.recency)}</span>;
    case "firstSource":
      return <span className="src">{o.firstSource}</span>;
    case "district":
      return <span className="pay">{o.district}</span>;
  }
}

function Row({
  o,
  cols,
  isOpen,
  isSel,
  colSpan,
  onToggle,
  onSelect,
}: {
  o: CustomerRecord;
  cols: ColumnDef[];
  isOpen: boolean;
  isSel: boolean;
  colSpan: number;
  onToggle: () => void;
  onSelect: () => void;
}) {
  return (
    <>
      <tr className={`orow${isOpen ? " open" : ""}${isSel ? " selected" : ""}`} onClick={onToggle}>
        <td><span className="exp-caret">▶</span></td>
        <td>
          <span
            className={`row-check${isSel ? " on" : ""}`}
            onClick={(e) => {
              e.stopPropagation();
              onSelect();
            }}
          />
        </td>
        {cols.map((c) => (
          <td key={c.k} className={c.num ? "num-cell" : ""}>{cellFor(o, c.k)}</td>
        ))}
      </tr>
      <tr className="detail-row">
        <td colSpan={colSpan}>
          <div className="detail-inner" style={{ maxHeight: isOpen ? 1400 : 0 }}>
            <Detail o={o} />
          </div>
        </td>
      </tr>
    </>
  );
}

