/* ───────────────────────── Date calendar popover ───────────────────────── */

const DOW = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];

function DateCalendar({
  preset,
  onPreset,
  onClose,
}: {
  preset: string;
  onPreset: (k: string) => void;
  onClose: () => void;
}) {
  const stop = (e: React.MouseEvent) => e.stopPropagation();
  const [view, setView] = useState<{ y: number; m: number }>({ y: 2026, m: 4 });
  const [pickStart, setPickStart] = useState<string | null>(null);
  const [pickEnd, setPickEnd] = useState<string | null>(null);

  const isoOf = (y: number, m: number, d: number) =>
    `${y}-${String(m + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;

  const pickDay = (iso: string) => {
    if (!pickStart || (pickStart && pickEnd)) {
      setPickStart(iso);
      setPickEnd(null);
    } else if (iso < pickStart) {
      setPickEnd(pickStart);
      setPickStart(iso);
    } else {
      setPickEnd(iso);
    }
    onPreset("custom");
  };

  const first = new Date(view.y, view.m, 1).getDay();
  const days = new Date(view.y, view.m + 1, 0).getDate();
  const prevDays = new Date(view.y, view.m, 0).getDate();
  const title = new Date(view.y, view.m, 1).toLocaleDateString("en-GB", { month: "long", year: "numeric" });

  const cells: React.ReactNode[] = [];
  for (let i = first - 1; i >= 0; i--) {
    cells.push(<div key={`p${i}`} className="cal-day muted">{prevDays - i}</div>);
  }
  for (let d = 1; d <= days; d++) {
    const iso = isoOf(view.y, view.m, d);
    let cls = "";
    if (pickStart && pickEnd) {
      if (iso === pickStart && iso === pickEnd) cls = "range-single";
      else if (iso === pickStart) cls = "range-start";
      else if (iso === pickEnd) cls = "range-end";
      else if (iso > pickStart && iso < pickEnd) cls = "in-range";
    } else if (pickStart && iso === pickStart) {
      cls = "range-single";
    }
    cells.push(
      <div
        key={iso}
        className={`cal-day ${cls}`}
        onClick={(e) => {
          e.stopPropagation();
          pickDay(iso);
        }}
      >
        {d}
      </div>,
    );
  }

  return (
    <div className="pop pop-date open" onClick={stop}>
      <div className="cal">
        <div className="cal-presets">
          {CAL_PRESETS.map((p) => (
            <button
              key={p.key}
              className={`cal-preset${preset === p.key ? " on" : ""}`}
              onClick={() => {
                onPreset(p.key);
                if (p.key !== "custom") {
                  setPickStart(null);
                  setPickEnd(null);
                }
              }}
            >
              {p.label}
            </button>
          ))}
        </div>
        <div className="cal-month-head">
          <button
            className="cal-nav"
            onClick={() => setView((c) => (c.m === 0 ? { y: c.y - 1, m: 11 } : { y: c.y, m: c.m - 1 }))}
          >
            ‹
          </button>
          <div className="cal-month-title">{title}</div>
          <button
            className="cal-nav"
            onClick={() => setView((c) => (c.m === 11 ? { y: c.y + 1, m: 0 } : { y: c.y, m: c.m + 1 }))}
          >
            ›
          </button>
        </div>
        <div className="cal-grid">
          {DOW.map((d) => <div key={d} className="cal-dow">{d}</div>)}
          {cells}
        </div>
        <div className="pop-foot">
          <button
            className="pop-btn"
            onClick={() => {
              setPickStart(null);
              setPickEnd(null);
              onPreset("all");
            }}
          >
            Clear
          </button>
          <button className="pop-btn primary" onClick={onClose}>Apply</button>
        </div>
      </div>
    </div>
  );
}
